const item = $json;

// Solo bloqueamos si es TRASH absoluto o si ya fue rechazado por Guard
if (item.category === 'trash' || item.trash === true) return [];

let score = 0;
// Scoring dinámico para el feed
if (item.category === 'evento') score += 50;
if (item.category === 'plaza') score += 20;
if (item.city && item.city !== 'Global') score += 15;
if ((item.text_es || '').length > 200) score += 10;

return [{ json: { ...item, final_score: score } }];

const item = $input.first()?.json || {};
function escapeHTML(text) { return String(text||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const langs = [
  { code: 'ES', tg: '-5283488138', title: item.title_es || 'Nuevo Lead', text: item.text_es || item.texto_limpio, tag: 'Remitente' }
];

const results = [];
for (const l of langs) {
  function formatOutputContact(val, mode) {
    if (!val || val === 'Desconocido' || val === 'No disponible') return 'No disponible';
    if (String(val).startsWith('tg_id_')) {
      const id = val.replace('tg_id_', '');
      return mode === 'html' ? `<a href="tg://user?id=${id}">Chat Directo</a>` : `ID: ${id}`;
    }
    if (/[a-zA-Z]/.test(val) && !/\d/.test(val)) {
       const user = String(val).replace('@', '');
       return mode === 'html' ? `<a href="https://t.me/${user}">@${user}</a>` : `@${user}`;
    }
    const s = String(val).replace(/[^0-9]/g, '');
    return s.length >= 7 ? `+${s}` : val;
  }

  const tgContact = formatOutputContact(item.contact || item.final_contact, 'html');

  const categoryStr = (item.category === 'plaza') ? 'Plazas' : 'Eventos';

  const tgText = `<b>${escapeHTML(l.title)}</b>\n🏷️ <b>${categoryStr}</b>\n📍 <b>${escapeHTML(item.city || 'Desconocida')}</b>\n💰 <b>${escapeHTML(item.budget || 'Negociable')}</b>\n\n${escapeHTML(l.text || 'Sin texto')}\n\n👤 <b>${l.tag}:</b> ${tgContact}\n🔌 <b>Fuente:</b> ${escapeHTML(item.platform || 'WhatsApp')}`;

  results.push({
    json: { ...item, route_lang: l.code, tg_chat: l.tg, tg_text: tgText }
  });
}
return results;

// DYNAMIC ROUTING ENGINE v7.0 (INPUT-BASED)
const leadData = $input.first().json;
const category = String(leadData.category || 'evento').toLowerCase();
const cityDetected = String(leadData.city || 'global').toLowerCase();
const text = String(leadData.text_es || '').toLowerCase();

const routingTable = {
  "madrid": {
    keywords: ["madrid", "barajas", "serrano", "pozuelo"],
    targets: [
      { to: "34664266926@s.whatsapp.net", label: "MADRID" },
      { to: "34603346859@s.whatsapp.net", label: "MADRID" },
      { to: "34647066645@s.whatsapp.net", label: "MADRID" }
    ]
  },
  "ibiza": {
    keywords: ["ibiza", "eivissa", "mansour", "pacha", "lio", "ushuaia", "sant antoni"],
    targets: [
      { to: "34662058447@s.whatsapp.net", label: "IBIZA" },
      { to: "34642107796@s.whatsapp.net", label: "IBIZA" }
    ]
  },
  "london": {
    keywords: ["london", "londres", "mayfair", "soho", "chelsea", "paddington", "canary wharf"],
    targets: [
      { to: "447444127962@s.whatsapp.net", label: "LONDON" }
    ]
  },
  "miami": {
    keywords: ["miami", "south beach", "brickell", "miami beach"],
    targets: [
      { to: "17862812324@s.whatsapp.net", label: "MIAMI" },
      { to: "525532110621@s.whatsapp.net", label: "MIAMI" }
    ]
  },
  "paris": {
    keywords: ["paris", "francia", "france", "champs"],
    targets: [
      { to: "33744156314@s.whatsapp.net", label: "PARIS" }
    ]
  },
  "monaco": {
    keywords: ["monaco", "viena", "vienna", "monte carlo"],
    targets: [
      { to: "120363425790792660@g.us", label: "GLOBAL" }
    ]
  },
  "dubai": {
    keywords: ["dubai", "uae", "emirates", "abu dhabi", "aed", "sharjah"],
    targets: [
      { to: "905344119396@s.whatsapp.net", label: "DUBAI" }
    ]
  }
};

let matchedTargets = [];

// 1. PRIORITY: Explicit City Match
if (routingTable[cityDetected]) {
    matchedTargets = [...routingTable[cityDetected].targets];
}

// 2. SECONDARY: Keyword Match
if (matchedTargets.length === 0) {
    for (const [key, config] of Object.entries(routingTable)) {
        if (config.keywords.some(kw => text.includes(kw))) {
             matchedTargets = [...matchedTargets, ...config.targets];
        }
    }
}

// 3. FALLBACK: Global feed
if (category === 'evento' || category === 'plaza') {
  matchedTargets.push({ to: "120363425790792660@g.us", label: (cityDetected !== 'global' ? cityDetected.toUpperCase() : 'GLOBAL') });
}

// Ensure unique targets
let uniqueTargets = Array.from(new Set(matchedTargets.map(t => t.to))).map(to => matchedTargets.find(t => t.to === to));

// DUBAI BUDGET FILTER
const dubaiTarget = "905344119396@s.whatsapp.net";
if (uniqueTargets.some(t => t.to === dubaiTarget)) {
  const combined = String(leadData.budget + " " + text).toLowerCase();
  const isNegotiable = combined.includes('negociable') || combined.includes('negotiable') || combined.includes('a convenir');
  const budgetMatch = combined.match(/\b\d{4,6}\b/);
  const highValue = budgetMatch && parseInt(budgetMatch[0]) >= 3000;

  if (!isNegotiable && !highValue) {
    uniqueTargets = uniqueTargets.filter(t => t.to !== dubaiTarget);
  }
}

return uniqueTargets.map(t => ({
  json: { 
    ...leadData, 
    target_wa: t.to, 
    city_label: t.label 
  }
}));

